update prompt
set view_count = coalesce(view_count, 0) + 1
where id = #{id}

update prompt
set favorite_count = coalesce(favorite_count, 0) + 1
where id = #{id}

update prompt
set like_count = coalesce(like_count, 0) + 1
where id = #{id}

update prompt
set copy_count = coalesce(copy_count, 0) + 1
where id = #{id}

update prompt
set view_count = coalesce(view_count, 0) + #{viewCount},
    like_count = coalesce(like_count, 0) + #{likeCount},
    favorite_count = coalesce(favorite_count, 0) + #{favoriteCount},
    copy_count = coalesce(copy_count, 0) + #{copyCount}
where id = #{promptId}
